```class Solution {
public:
    string frequencySort(string s) {
        unordered_map<char, int> freq;
        for (char c : s) {
            freq[c]++;
        }
        vector<pair<int, char>> v;
        for (auto p : freq) {
            v.push_back({p.second, p.first});
        }
        sort(v.rbegin(), v.rend());
        string res;
        for (auto p : v) {
            while (p.first--) {
                res += p.second;
            }
        }
        return res;
    }
};```
